import sys
import os
sys.path.insert(0, os.path.join(os.path.dirname(__file__), 'src'))

from marshmallow import Schema, fields, validates, ValidationError

print("Test 1: Original issue - nested field with validator, invalid input")
class Bar(Schema):
    value = fields.String()

    @validates('value')
    def validate_value(self, value):
        if value == 'bad':
            raise ValidationError('value cannot be bad')

class Foo(Schema):
    bar = fields.Nested(Bar)

sch = Foo()
errors = sch.validate({'bar': 'invalid'})
print(f"  Errors: {errors}")
assert errors == {'bar': {'_schema': ['Invalid input type.']}}

print("\nTest 2: Nested field with validator, valid input")
errors = sch.validate({'bar': {'value': 'good'}})
print(f"  Errors: {errors}")
assert errors == {}

print("\nTest 3: Nested field with validator, invalid nested value")
errors = sch.validate({'bar': {'value': 'bad'}})
print(f"  Errors: {errors}")
assert 'bar' in errors and 'value' in errors['bar']

print("\nTest 4: Direct field with validator, invalid input")
class Simple(Schema):
    value = fields.String()

    @validates('value')
    def validate_value(self, value):
        if value == 'bad':
            raise ValidationError('value cannot be bad')

simple_sch = Simple()
errors = simple_sch.validate({'value': 'bad'})
print(f"  Errors: {errors}")
assert 'value' in errors

print("\nTest 5: Schema-level validator with invalid nested input")
class Foo2(Schema):
    bar = fields.Nested(Bar)

    @validates_schema
    def validate_schema(self, data):
        if data.get('bar', {}).get('value') == 'schema_bad':
            raise ValidationError('schema validation failed')

sch2 = Foo2()
errors = sch2.validate({'bar': 'invalid'})
print(f"  Errors: {errors}")
assert errors == {'bar': {'_schema': ['Invalid input type.']}}

print("\nTest 6: Many=True case with invalid input")
class FooMany(Schema):
    bars = fields.Nested(Bar, many=True)

sch_many = FooMany()
errors = sch_many.validate({'bars': 'invalid'})
print(f"  Errors: {errors}")
assert errors == {'bars': {'_schema': ['Invalid input type.']}}

print("\nTest 7: Many=True case with list containing invalid item")
errors = sch_many.validate({'bars': ['invalid']})
print(f"  Errors: {errors}")
assert 'bars' in errors and 0 in errors['bars']

print("\nAll tests passed!")
EOF"}

